19	const PROCESSING_FEE = 5;
20	const FIRST_INSURANCE_RATE = 0.1;
21	
22	const BASE_PREMIUM: Record<string, number> = {
23	  sword: 100,
24	  amulet: 60,
25	  staff: 80,
26	  potion: 40,
27	  rune: 25,
28	};
29	
30	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
31	const BLOCK_SIZE = 3;
32	const BLOCK_BASE_PREMIUM = 60;
33	
34	const itemsBaseForType = (type: string, count: number): number => {
35	  if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) return BLOCK_BASE_PREMIUM;
36	  return count * BASE_PREMIUM[type];
37	};
38	
39	const policyBase = (items: Item[]): number => {
40	  const counts = new Map<string, number>();
41	  for (const item of items) counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
42	  let total = 0;
43	  for (const [type, count] of counts) total += itemsBaseForType(type, count);
44	  return total;
45	};
46	
47	const quoteStep = (step: QuoteStep): QuoteResult => {
48	  const base = policyBase(step.items);
49	  const firstInsurance = base * FIRST_INSURANCE_RATE;
50	  return { premium: Math.ceil(base + firstInsurance + PROCESSING_FEE) };
51	};
52	
53	export const processScenario = (scenario: Scenario): { results: QuoteResult[] } => {
54	  const results = scenario.steps.map(quoteStep);
55	  return { results };
56	};
